// // This module decrements a 4-bit binary counter on every positive edge of the input clock signal and resets to 7 when the reset signal is high.
module bin_counter(
    input       clk,
    input       rst,
    output reg [3:0] count
);

    always @(posedge clk or posedge rst) begin
        if(rst) begin
            count <= 4'b0000;
        end
        else begin
            count <= count + 1;
        end
    end

endmodule
